arguments.argument:
waterFrame+=image_speed

if global.gamePaused=false
{
  if bSelfControl=1
  {
    if y>targetWLevel
      y-=2
    else if y<targetWLevel
      y+=2
  }
}

if global.debugMenu=true
{
  if keyboard_check(ord("R"))
  {
    targetWLevel-=2
    y-=2
  }
  else if keyboard_check(ord("F"))
  {
    targetWLevel+=2
    y+=2
  }
}
